def build_group_standing_caption(group_title, rows):
    lines = [f"🏆 {group_title}", ""]
    for i, (team, played, diff, pts) in enumerate(rows, start=1):
        lines.append(f"{i}. {team} — لعب {played} | فارق {diff:+d} | نقاط {pts}")
    lines.append("\nالمصيف ينقل لكم الحدث")
    return "\n".join(lines)

