            data = await asyncio.wait_for(asyncio.to_thread(serpapi_search_json, "مباراة المكسيك كوريا الجنوبية", "ar", "sa", 8), timeout=12)
            lines.append("✅ SERPAPI_KEY موجود والاتصال بقوقل شغال")
